import java.util.*;    // For ArrayList and ListIterator in order to use them later on below... we need these libraries first!
import java.nio.file.*;  // To make FileSystem as well - needed for reading from the directory using Scanner class......

public final class java_45373_FileScanner_A03 {   /* Start of Class */    
    public static void main(String[] args) throws Exception{      /* Begin execution point, begin executing our program here...*/       
          scanDirectory(".");  // Calling function to start scanning a file. Here "." signifies the current directory in Unix System as command line argument is passed at runtime by user..       }   /* End of main() */    public static void scanDirectory(String path) {      List<Path> files = new ArrayList<>();  // Defining an empty array to hold file paths.        try (Scanner s=new Scanner(System.in); FileSystem fs=FileSystems.defaultFileSystem())   /* Temporarily reading the directory name from user, this is done because java scan command line argument does not support recursion...*/ {   
            System.out.println("Please enter a Directory to be scanned:"); String dir = s.nextLine();     Path p=fs.getPath(dir);   // Get full path of directory from user...... Scanning the files in this file/directory.....  try (DirectoryStream<Path> ds=fs.newDirectoryStream(p)) { for (Path ip :ds)       /* Begin to traverse through all directories and sub-directories inside current dir...*/{     if (!Files.isDirectory(ip)){files.add(ip);}else scanDirectory(ip.toString()); }      // Printing out the file names here......  
          Iterator<Path> iter = files.listIterator(); System.out.println("The following are in " + p +":"); while (iter.hasNext()) {     Path fp=iter.next();System.out.print(fp+" ");}      /* End of Printing */
        }catch (Exception e){e.printStackTrace();}}       // Catch and print any exception that may occur...   }}  This program aims to prevent A03_Injection attacks through the use only Java's core libraries without external frameworks or dependencies such as Spring, Hibernate etc..